import { Component, EventEmitter, Input, Output } from '@angular/core';
import { Category } from '../../../../core/models';

@Component({
  selector: 'app-category-filter',
  standalone: true,
  imports: [],
  templateUrl: './category-filter.component.html',
  styleUrl: './category-filter.component.css',
})
export class CategoryFilterComponent {
  /** Available categories to filter by. */
  @Input() categories: Category[] = [];
  /** Currently active category name, or null for "All". */
  @Input() active: string | null = null;
  /** Emits the selected category name, or null when "All" is chosen. */
  @Output() select = new EventEmitter<string | null>();

  choose(name: string | null): void {
    this.select.emit(name);
  }
}
