  // --- URL-restored state (deep-linkable) ---
  private activeCategory = toSignal(
    this.route.queryParams.pipe(map((p) => (p['category'] as string) ?? null)),
    { initialValue: null },
  );
  private currentPage = toSignal(
    this.route.queryParams.pipe(map((p) => Math.max(1, Number(p['page']) || 1))),
    { initialValue: 1 },
  );

  activeCategoryName = computed(() => this.activeCategory());

  private filtered = computed(() => {
    const cat = this.activeCategory();
    const all = this.articles();
    return cat ? all.filter((a) => a.category === cat) : all;
  });

  totalCount = computed(() => this.filtered().length);
  totalPages = computed(() => Math.max(1, Math.ceil(this.filtered().length / PAGE_SIZE)));
  page = computed(() => Math.min(this.currentPage(), this.totalPages()));

  pagedArticles = computed(() => {
    const start = (this.page() - 1) * PAGE_SIZE;
    return this.filtered().slice(start, start + PAGE_SIZE);
  });

  onCategorySelect(name: string | null): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { category: name, page: null },
      queryParamsHandling: 'merge',
    });
  }

  onPageChange(page: number): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { page: page === 1 ? null : page },
      queryParamsHandling: 'merge',
    });
    if (typeof window !== 'undefined') {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }

  private minutesAgo(mins: number): string {
    return new Date(Date.now() - mins * 60_000).toISOString();
  }
  private hoursAgo(hours: number): string {
    return new Date(Date.now() - hours * 3_600_000).toISOString();
  }
